#include &lt;stdio.h&gt;
#include &lt;stdint.h&gt;

int main() {
    uint32_t eax, ebx, ecx, edx;

    // CPUID is an x86 instruction that returns processor info.
    // We pass 0 into EAX before calling it to request the "Vendor ID".
    // The CPU will write a 12-character ASCII string across EBX, EDX, and ECX.

    eax = 0;

    __asm__ __volatile__ (
        "cpuid\n\t"
        : "=a" (eax), "=b" (ebx), "=c" (ecx), "=d" (edx) // Output constraints
        : "0" (eax)                                      // Input: 0 binds to the %0 slot (eax)
    );

    // The vendor string is physically loaded into the registers.
    // We must assemble them sequentially (EBX, then EDX, then ECX).
    char vendor[13];
    uint32_t *ptr = (uint32_t *)vendor;
    ptr[0] = ebx;
    ptr[1] = edx; // Notice EDX comes before ECX in the Intel spec!
    ptr[2] = ecx;
    vendor[12] = '\0';

    printf("CPU Vendor: %s\n", vendor); // e.g., "GenuineIntel" or "AuthenticAMD"
    return 0;
}

#include &lt;stdint.h&gt;

void write_hardware_port(uint16_t port, uint64_t huge_data) {
    // Engineer wants to write 64 bits to a hardware port.
    // They correctly map the port to DX and data to EAX.
    __asm__ __volatile__ (
        "outl %0, %1"
        : 
        : "a" (huge_data), "d" (port)
    );
}

#include &lt;stdio.h&gt;
#include &lt;stdint.h&gt;

void secure_math_operation(uint64_t *array, size_t count) {
    uint64_t total = 0;

    __asm__ __volatile__ (
        // We manually loop and accumulate into %0.
        // We are using 'rcx' as a loop counter, which is NOT mapped to a C variable.
        "mov rcx, %2\n\t"
        "1:\n\t"                   // Label 1
        "add %0, [%1 + rcx*8]\n\t" // Add array element to total
        "dec rcx\n\t"              // Decrement loop counter (destroys CPU Flags!)
        "jns 1b"                   // Jump backward to 1 if not sign (rcx >= 0)

        : "+r" (total)             // Output (+ means read/write)
        : "r" (array), "r" (count) // Inputs

        // The Clobber List:
        // 1. We destroyed rcx. We must declare it.
        // 2. 'dec' destroys CPU Condition Codes (Flags). We must declare "cc".
        // 3. We read from random memory pointers. We declare "memory".
        : "rcx", "cc", "memory"
    );

    printf("Total: %lu\n", total);
}
